/* ---------- response parsing helpers ---------- */
function parseResponse(data) {
  const content = Array.isArray(data?.content) ? data.content : [];
  const text = content
    .filter((b) => b?.type === "text")
    .map((b) => b.text)
    .join("\n")
    .trim();

  const sources = [];
  const seen = new Set();
  const consider = (o) => {
    if (o && o.url && !seen.has(o.url)) {
      seen.add(o.url);
      sources.push({ title: o.title || o.url, url: o.url });
    }
  };
  for (const b of content) {
    if (Array.isArray(b?.content)) b.content.forEach(consider);
    if (Array.isArray(b?.citations)) b.citations.forEach(consider);
  }
  return { text, sources };
}

function extractJSON(text) {
  if (!text) return null;
  const s = text.indexOf("{");
  if (s === -1) return null;
  let depth = 0, inStr = false, esc = false;
  for (let i = s; i < text.length; i++) {
    const ch = text[i];
    if (inStr) {
      if (esc) esc = false;
      else if (ch === "\\") esc = true;
      else if (ch === '"') inStr = false;
    } else if (ch === '"') inStr = true;
    else if (ch === "{") depth++;
    else if (ch === "}") {
      depth--;
      if (depth === 0) {
        try { return JSON.parse(text.slice(s, i + 1)); } catch { return null; }
      }
    }
  }
  return null; // unbalanced / truncated
}

async function callClaude(body) {
  const res = await fetch(ENDPOINT, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ model: MODEL, max_tokens: 2000, ...body }),
  });
  if (!res.ok) throw new Error("Request failed (" + res.status + ")");
  return res.json();
}

const WEB_TOOL = [{ type: "web_search_20250305", name: "web_search" }];

/* Read a pre-generated section from the cache (instant, no model call). */
async function readCache(section) {
  try {
    const r = await fetch("/api/cache?section=" + encodeURIComponent(section));
    if (!r.ok) return null;
    const j = await r.json();
    return j && j.content ? j.content : null;
  } catch {
    return null;
  }
}

/* ---------- count-up animation ---------- */
function useCountUp(target, dur = 1300) {
  const [v, setV] = useState(0);
  useEffect(() => {
    if (target == null) return;
    let raf, start;
    const step = (t) => {
      if (!start) start = t;
      const p = Math.min((t - start) / dur, 1);
      const eased = 1 - Math.pow(1 - p, 3);
      setV(Math.round(target * eased));
      if (p < 1) raf = requestAnimationFrame(step);
    };
    raf = requestAnimationFrame(step);
    return () => cancelAnimationFrame(raf);
  }, [target, dur]);
  return v;
}

/* ---------- sentiment color scale ---------- */
function sentColor(score) {
  if (score == null) return "var(--ink-faint)";
  if (score >= 60) return "var(--pos)";
  if (score >= 45) return "var(--neu)";
  return "var(--neg)";
}

/* ---------- light markdown renderer ---------- */
function renderRich(text) {
  if (!text) return null;
  const lines = text.split("\n");
  const out = [];
  let bullets = [];
  const flush = (key) => {
    if (bullets.length) {
      out.push(
        <ul className="ct-ul" key={"ul" + key}>
          {bullets.map((b, i) => (
            <li key={i}>{inline(b)}</li>
          ))}
        </ul>
      );
      bullets = [];
    }
  };
  lines.forEach((raw, idx) => {
    const line = raw.trim();
    if (!line) {
      flush(idx);
      return;
    }
    const bm = line.match(/^(?:[-*•]|\d+\.)\s+(.*)$/);
    if (bm) {
      bullets.push(bm[1]);
      return;
    }
    flush(idx);
    if (/^#{1,6}\s/.test(line)) {
      out.push(
        <p className="ct-subhead" key={idx}>
          {inline(line.replace(/^#{1,6}\s/, ""))}
        </p>
      );
    } else {
      out.push(
        <p className="ct-p" key={idx}>
          {inline(line)}
        </p>
      );
    }
  });
  flush("end");
  return out;
}
function inline(str) {
  const parts = str.split(/(\*\*[^*]+\*\*|`[^`]+`)/g);
  return parts.map((p, i) => {
    if (/^\*\*[^*]+\*\*$/.test(p)) return <strong key={i}>{p.slice(2, -2)}</strong>;
    if (/^`[^`]+`$/.test(p)) return <code className="ct-code" key={i}>{p.slice(1, -1)}</code>;
    return <React.Fragment key={i}>{p}</React.Fragment>;
  });
}

/* ============================================================
   SENTIMENT GAUGE (hand-built SVG semicircle)
   ============================================================ */
function Gauge({ score }) {
  const animated = useCountUp(score ?? 0);
  const R = 88;
  const CIRC = Math.PI * R; // semicircle length
  const frac = (score ?? 0) / 100;
  return (
    <div className="ct-gauge">
      <svg viewBox="0 0 220 130" width="100%" height="100%">
        <defs>
          <linearGradient id="gg" x1="0" y1="0" x2="1" y2="0">
            <stop offset="0%" stopColor="var(--neg)" />
            <stop offset="50%" stopColor="var(--neu)" />
            <stop offset="100%" stopColor="var(--pos)" />
          </linearGradient>
        </defs>
        <path
          d="M 22 116 A 88 88 0 0 1 198 116"
          fill="none"
          stroke="var(--track)"
          strokeWidth="14"
          strokeLinecap="round"
        />
        <path
          d="M 22 116 A 88 88 0 0 1 198 116"
          fill="none"
          stroke="url(#gg)"
          strokeWidth="14"
          strokeLinecap="round"
          strokeDasharray={CIRC}
          strokeDashoffset={CIRC * (1 - frac)}
          style={{ transition: "stroke-dashoffset 1.3s cubic-bezier(.2,.8,.2,1)" }}
        />
      </svg>
      <div className="ct-gauge-readout">
        <div className="ct-gauge-num" style={{ color: sentColor(score) }}>
          {score == null ? "-" : animated}
        </div>
        <div className="ct-gauge-cap">INDEX / 100</div>
      </div>
    </div>
  );
}

/* ============================================================
   "Thinking" status phrases (shared by the loader)
   ============================================================ */
const THINK_PHRASES = [
  "Scanning recent headlines",
  "Weighing market signals",
  "Reading policy shifts",
  "Gauging public mood",
  "Synthesizing the index",
];

/* ============================================================
   PARTICLE DISC, contained, monochrome "instrument" loader
   Soft points drifting + twinkling within a circular field.
   ============================================================ */
function GaugeLoading({ theme }) {
  const canvasRef = useRef(null);
  const themeRef = useRef(theme);
  useEffect(() => { themeRef.current = theme; }, [theme]);
  const [phrase, setPhrase] = useState(0);

  useEffect(() => {
    const id = setInterval(() => setPhrase((p) => (p + 1) % THINK_PHRASES.length), 1700);
    return () => clearInterval(id);
  }, []);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext("2d");
    let raf, W = 0, H = 0, frame = 0, parts = [], R = 0;

    function build() {
      R = Math.min(W, H) / 2 - 5;
      const count = Math.max(70, Math.round((R * R) / 52));
      parts = Array.from({ length: count }, () => {
        const ang = Math.random() * 6.2832;
        const rad = R * Math.sqrt(Math.random());
        return {
          x: W / 2 + Math.cos(ang) * rad,
          y: H / 2 + Math.sin(ang) * rad,
          vx: (Math.random() - 0.5) * 0.18,
          vy: (Math.random() - 0.5) * 0.18,
          size: Math.random() < 0.86 ? 0.7 + Math.random() * 0.9 : 1.5 + Math.random() * 1.1,
          base: 0.22 + Math.random() * 0.55,
          tw: 0.4 + Math.random() * 1.4,
          ph: Math.random() * 6.2832,
        };
      });
    }

    function setup() {
      const dpr = Math.min(window.devicePixelRatio || 1, 2);
      const rect = canvas.getBoundingClientRect();
      W = rect.width; H = rect.height;
      if (!W || !H) return;
      canvas.width = W * dpr; canvas.height = H * dpr;
      ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
      build();
    }

    function draw() {
      raf = requestAnimationFrame(draw);
      try {
        if (!parts.length) { setup(); return; }
        frame++;
        const cx = W / 2, cy = H / 2, t = frame * 0.016;
        ctx.clearRect(0, 0, W, H);
        for (const p of parts) {
          // gentle brownian drift, softly bounded to the disc
          p.vx = (p.vx + (Math.random() - 0.5) * 0.03) * 0.97;
          p.vy = (p.vy + (Math.random() - 0.5) * 0.03) * 0.97;
          p.x += p.vx; p.y += p.vy;
          const dx = p.x - cx, dy = p.y - cy;
          const d = Math.sqrt(dx * dx + dy * dy) || 0.001;
          if (d > R) { const f = (d - R) * 0.04; p.vx -= (dx / d) * f; p.vy -= (dy / d) * f; }
          const edge = 1 - Math.pow(Math.min(d / R, 1), 4); // soft fade at the rim
          const tw = 0.45 + 0.55 * Math.sin(t * p.tw + p.ph);
          const a = p.base * tw * edge;
          if (a <= 0.01) continue;
          ctx.fillStyle = "rgba(" + (themeRef.current === "light" ? "60,78,58" : "234,238,232") + "," + a.toFixed(3) + ")";
          ctx.beginPath(); ctx.arc(p.x, p.y, p.size, 0, 6.2832); ctx.fill();
        }
      } catch (e) {
        cancelAnimationFrame(raf);
      }
    }

    setup();
    draw();
    let ro;
    if (typeof ResizeObserver !== "undefined") { ro = new ResizeObserver(() => setup()); ro.observe(canvas); }
    else window.addEventListener("resize", setup);
    return () => {
      cancelAnimationFrame(raf);
      if (ro) ro.disconnect(); else window.removeEventListener("resize", setup);
    };
  }, []);

  return (
    <div className="ct-disc-wrap">
      <canvas ref={canvasRef} className="ct-disc" />
      <div className="ct-disc-cap" key={phrase}>
        <span className="ct-neural-phrase">{THINK_PHRASES[phrase]}</span><span className="ct-ellipsis" />
      </div>
    </div>
  );
}

