const SENT_SCHEMA =
  '{"overall":{"score":<int 0-100>,"label":"<2-3 words>","summary":"<<=20 words>"},' +
  '"categories":[{"name":"Medical","score":<int>,"label":"<1-2 words>","note":"<<=14 words>",' +
  '"headline":"<short real headline>","source":"<outlet>"}],"asOf":"<Month Year>"}';

async function pullJSON(sysBase, userText, validate) {
  for (const strict of [false, true]) {
    const sys = sysBase + (strict
      ? " Return ONLY minified JSON on one line, no prose, no code fences, no trailing text."
      : " Respond with ONLY a JSON object, no markdown, no commentary.");
    try {
      const resp = await callClaude({ system: sys, tools: WEB_TOOL, messages: [{ role: "user", content: userText }] });
      const { text } = parseResponse(resp);
      const j = extractJSON(text);
      if (j && validate(j)) return j;
    } catch { /* try next */ }
  }
  return null;
}

async function pullSentiment() {
  return { json: await readCache("sentiment"), est: false };
}

async function pullMarket() {
  return readCache("market");
}

function daysUntil(dateStr) {
  if (!dateStr) return null;
  const then = Date.parse(dateStr);
  if (isNaN(then)) return null;
  return Math.round((then - Date.now()) / 86400000);
}

async function pullMedia() {
  return readCache("media");
}

function faviconFor(url) {
  try { return "https://www.google.com/s2/favicons?domain=" + new URL(url).hostname + "&sz=64"; }
  catch { return null; }
}
const tagColor = (t) => (t === "bull" ? "var(--pos)" : t === "bear" ? "var(--neg)" : "var(--neu)");

function getYouTubeId(url) {
  if (!url) return null;
  const m = String(url).match(/(?:v=|youtu\.be\/|shorts\/|embed\/)([A-Za-z0-9_-]{11})/);
  return m ? m[1] : null;
}

/* ---------- next-phase desk pulls (Healthcare, Catalysts, Home, Briefings) ---------- */
function fmtDate(s) {
  const t = Date.parse(s);
  if (isNaN(t)) return s || "TBD";
  return new Date(t).toLocaleDateString("en-US", { month: "short", day: "numeric" });
}
function whenLabel(s) {
  const d = daysUntil(s);
  if (d == null) return "";
  if (d < 0) return "PAST";
  if (d === 0) return "TODAY";
  if (d === 1) return "TOMORROW";
  if (d <= 120) return "IN " + d + "D";
  return "";
}
const impactColor = (i) =>
  i === "high" ? "var(--accent)" : i === "medium" ? "var(--neu)" : "var(--ink-faint)";

