function SectorMovers({ tickers, sel, onSel }) {
  const max = Math.max(1, ...tickers.map((t) => Math.abs(Number(t.changePct) || 0)));
  return (
    <div className="ct-movers">
      {tickers.map((t, i) => {
        const v = Number(t.changePct) || 0;
        const up = v >= 0;
        const w = Math.min(49, (Math.abs(v) / max) * 49);
        const price = typeof t.price === "number" ? "$" + t.price.toFixed(2) : t.price || "-";
        const active = sel === t.symbol;
        return (
          <div
            className={"ct-mv-row ct-rise" + (active ? " ct-mv-on" : "")}
            key={(t.symbol || i) + i}
            style={{ animationDelay: i * 55 + "ms" }}
            onClick={() => onSel && onSel(t.symbol)}
            role="button"
          >
            <div className="ct-mv-top">
              <div className="ct-mv-id">
                <span className="ct-mv-sym">{t.symbol}</span>
                <span className="ct-mv-name">{t.name}</span>
              </div>
              <span className="ct-mv-price">{price}</span>
              <span className="ct-mv-val" style={{ color: up ? "var(--pos)" : "var(--neg)" }}>
                {up ? "▲ " : "▼ "}{up ? "+" : ""}{v.toFixed(1)}%
              </span>
            </div>
            <div className="ct-mv-track">
              <span className="ct-mv-mid" />
              <span
                className="ct-mv-bar"
                style={{
                  width: w + "%",
                  background: up ? "var(--pos)" : "var(--neg)",
                  left: up ? "50%" : "auto",
                  right: up ? "auto" : "50%",
                }}
              />
            </div>
            {t.driver ? <div className="ct-mv-driver">{t.driver}</div> : null}
          </div>
        );
      })}
    </div>
  );
}

