/* ============================================================
   TICKER BOARD, clickable strip + on-demand price chart
   Series are AI-sourced via web search (indicative, not a feed).
   ============================================================ */
async function pullSeries(symbol) {
  // Real 30-day history (Twelve Data), pre-fetched into the cache by the daily refresh.
  return readCache("series_" + symbol);
}

function MiniChart({ series }) {
  const pts = series.points;
  const W = 680, H = 210, pad = 10;
  const cs = pts.map((p) => p.c);
  const min = Math.min(...cs), max = Math.max(...cs), span = max - min || 1;
  const n = pts.length;
  const X = (i) => pad + (W - 2 * pad) * (n === 1 ? 0.5 : i / (n - 1));
  const Y = (c) => pad + (H - 2 * pad) * (1 - (c - min) / span);
  const up = cs[n - 1] >= cs[0];
  const color = up ? "var(--pos)" : "var(--neg)";
  const line = pts.map((p, i) => (i ? "L" : "M") + X(i).toFixed(1) + " " + Y(p.c).toFixed(1)).join(" ");
  const area = "M" + X(0).toFixed(1) + " " + (H - pad) + " " +
    pts.map((p, i) => "L" + X(i).toFixed(1) + " " + Y(p.c).toFixed(1)).join(" ") +
    " L" + X(n - 1).toFixed(1) + " " + (H - pad) + " Z";
  return (
    <div className="ct-chartwrap">
      <svg className="ct-chartsvg" viewBox={"0 0 " + W + " " + H} preserveAspectRatio="none">
        <defs>
          <linearGradient id="ctArea" x1="0" y1="0" x2="0" y2="1">
            <stop offset="0%" stopColor={color} stopOpacity="0.3" />
            <stop offset="100%" stopColor={color} stopOpacity="0" />
          </linearGradient>
        </defs>
        <path d={area} fill="url(#ctArea)" />
        <path d={line} fill="none" stroke={color} strokeWidth="2" strokeLinejoin="round" strokeLinecap="round" vectorEffect="non-scaling-stroke" />
      </svg>
      <span className="ct-chart-hi">{max.toFixed(2)}</span>
      <span className="ct-chart-lo">{min.toFixed(2)}</span>
    </div>
  );
}

function TickerBoard({ tickers, sel, onSel }) {
  const [cache, setCache] = useState({});
  const fetched = useRef({});
  useEffect(() => {
    if (!sel || fetched.current[sel]) return;
    fetched.current[sel] = true;
    let cancelled = false;
    setCache((c) => ({ ...c, [sel]: { loading: true } }));
    const t = tickers.find((x) => x.symbol === sel);
    pullSeries(sel, t && t.name)
      .then((data) => { if (!cancelled) setCache((c) => ({ ...c, [sel]: data ? { data } : { error: true } })); })
      .catch(() => { if (!cancelled) setCache((c) => ({ ...c, [sel]: { error: true } })); });
    return () => { cancelled = true; };
  }, [sel, tickers]);

  const cur = sel ? cache[sel] : null;
  const t = tickers.find((x) => x.symbol === sel);
  const chg = t ? Number(t.changePct) || 0 : 0;

  return (
    <div className="ct-board">
      <div className="ct-tape">
        {tickers.map((x) => {
          const v = Number(x.changePct) || 0, up = v >= 0;
          return (
            <button key={x.symbol} className={"ct-tape-item" + (x.symbol === sel ? " on" : "")} onClick={() => onSel(x.symbol)}>
              <span className="ct-tape-sym">{x.symbol}</span>
              <span className="ct-tape-chg" style={{ color: up ? "var(--pos)" : "var(--neg)" }}>{up ? "+" : ""}{v.toFixed(1)}%</span>
            </button>
          );
        })}
      </div>
      <div className="ct-chart-card">
        {t && (
          <div className="ct-chart-head">
            <div className="ct-chart-id">
              <span className="ct-chart-sym">{t.symbol}</span>
              <span className="ct-chart-name">{t.name}</span>
            </div>
            <div className="ct-chart-quote">
              <span className="ct-chart-price">{typeof t.price === "number" ? "$" + t.price.toFixed(2) : t.price || ""}</span>
              <span className="ct-chart-chg" style={{ color: chg >= 0 ? "var(--pos)" : "var(--neg)" }}>{chg >= 0 ? "▲ +" : "▼ "}{chg.toFixed(1)}%</span>
            </div>
          </div>
        )}
        <div className="ct-chart-body">
          {(!cur || cur.loading) && <div className="ct-chart-load"><span className="ct-spinner" /> loading {sel} closes…</div>}
          {cur && cur.error && <div className="ct-mini-err">Couldn't load a chart for {sel} right now.</div>}
          {cur && cur.data && <MiniChart series={cur.data} />}
        </div>
        <div className="ct-chart-foot">
          DAILY CLOSES · MARKET DATA, MAY BE DELAYED{cur && cur.data && cur.data.asOf ? " · " + cur.data.asOf.toUpperCase() : ""}
        </div>
      </div>
    </div>
  );
}

/* ============================================================
   DESK BRIEF, AI analyst note synthesized from our own signals
   ============================================================ */
async function pullBrief(ctx) {
  const sys =
    "You are the lead analyst on a cannabis-sector desk writing a crisp morning note for investors. " +
    "Using ONLY the data provided, return ONLY minified JSON: " +
    '{"thesis":"<one sharp sentence, <=24 words>","drivers":["<=14 words","<=14 words","<=14 words"],"stance":"<Constructive|Neutral|Cautious|Bullish|Bearish>, <=10 words>"}. ' +
    "Reference real tickers, catalysts and numbers from the data. Punchy and specific. No hedging, no disclaimers, no markdown.";
  try {
    const resp = await callClaude({ system: sys, max_tokens: 700, messages: [{ role: "user", content: "DATA:\n" + ctx }] });
    return extractJSON(parseResponse(resp).text);
  } catch { return null; }
}

/* ============================================================
   LIVE CLOCK + PRICE TAPE, terminal flourishes
   ============================================================ */
function Clock() {
  const [t, setT] = useState(() => new Date());
  useEffect(() => {
    const id = setInterval(() => setT(new Date()), 1000);
    return () => clearInterval(id);
  }, []);
  const p = (n) => String(n).padStart(2, "0");
  return <span className="ct-clock">{p(t.getHours())}:{p(t.getMinutes())}:{p(t.getSeconds())}</span>;
}

function PriceTape({ tickers, index, onSel }) {
  const items = [];
  if (index && index.symbol) items.push({ symbol: index.symbol, price: index.price, changePct: index.changePct });
  (tickers || []).forEach((t) => items.push(t));
  if (!items.length) return null;
  const seq = items.concat(items, items);
  return (
    <div className="ct-tape2">
      <div className="ct-tape2-tag"><span className="ct-live-dot" /> LIVE <Clock /></div>
      <div className="ct-tape2-vp">
        <div className="ct-tape2-track" style={{ animationDuration: Math.max(30, items.length * 6) + "s" }}>
          {seq.map((t, i) => {
            const v = Number(t.changePct) || 0, up = v >= 0;
            return (
              <button className="ct-tape2-item" key={i} onClick={() => onSel && onSel(t.symbol)}>
                <span className="ct-tape2-sym">{t.symbol}</span>
                <span className="ct-tape2-px">{typeof t.price === "number" ? "$" + t.price.toFixed(2) : ""}</span>
                <span className="ct-tape2-chg" style={{ color: up ? "var(--pos)" : "var(--neg)" }}>{up ? "▲" : "▼"} {up ? "+" : ""}{v.toFixed(1)}%</span>
              </button>
            );
          })}
        </div>
      </div>
    </div>
  );
}

/* ============================================================
   HEADER WIDGETS, live stat tiles + sector constellation
   ============================================================ */
function StatTile({ label, value, sub, delta, deltaColor, children }) {
  return (
    <div className="ct-tile">
      <div className="ct-tile-label">{label}</div>
      <div className="ct-tile-main">
        <span className="ct-tile-value">{value}</span>
        {delta != null ? <span className="ct-tile-delta" style={{ color: deltaColor }}>{delta}</span> : null}
      </div>
      <div className="ct-tile-foot">{sub}{children}</div>
    </div>
  );
}

function StatStrip({ mkt, loading }) {
  if (loading) {
    return (
      <div className="ct-stats">
        {Array.from({ length: 4 }).map((_, i) => <div className="ct-tile ct-tile-skel" key={i} />)}
      </div>
    );
  }
  if (!mkt) return null;
  const tickers = mkt.tickers || [];
  const adv = tickers.filter((t) => (Number(t.changePct) || 0) > 0).length;
  const dec = tickers.filter((t) => (Number(t.changePct) || 0) < 0).length;
  const tot = Math.max(1, adv + dec);
  const top = tickers.slice().sort((a, b) => Math.abs(Number(b.changePct) || 0) - Math.abs(Number(a.changePct) || 0))[0];
  const idx = mkt.index || {};
  const idxChg = Number(idx.changePct) || 0;
  const cat = mkt.catalyst || {};
  const d = daysUntil(cat.date);
  const topChg = top ? Number(top.changePct) || 0 : 0;

  return (
    <div className="ct-stats">
      <StatTile
        label="SECTOR INDEX"
        value={typeof idx.price === "number" ? "$" + idx.price.toFixed(2) : idx.symbol || "-"}
        delta={(idxChg >= 0 ? "+" : "") + idxChg.toFixed(1) + "%"}
        deltaColor={idxChg >= 0 ? "var(--pos)" : "var(--neg)"}
        sub={idx.symbol || "ETF"}
      />
      <StatTile label="BREADTH" value={adv + " ▲"} sub={dec + " ▼ today"}>
        <div className="ct-breadth"><span style={{ width: (adv / tot) * 100 + "%" }} /></div>
      </StatTile>
      <StatTile
        label="NEXT CATALYST"
        value={d != null ? (d <= 0 ? "NOW" : d + "d") : "-"}
        sub={cat.label || "-"}
      >
        <span className="ct-cat-dot" />
      </StatTile>
      <StatTile
        label="TOP MOVER"
        value={top ? top.symbol : "-"}
        delta={top ? (topChg >= 0 ? "+" : "") + topChg.toFixed(1) + "%" : null}
        deltaColor={topChg >= 0 ? "var(--pos)" : "var(--neg)"}
        sub={top ? top.name : ""}
      />
    </div>
  );
}

function Constellation({ tickers, sel, onSel, theme }) {
  const canvasRef = useRef(null);
  const selRef = useRef(sel);
  const themeRef = useRef(theme);
  useEffect(() => { themeRef.current = theme; }, [theme]);
  const hoverRef = useRef(null);
  useEffect(() => { selRef.current = sel; }, [sel]);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext("2d");
    let raf, W = 0, H = 0, frame = 0, orbs = [];
    const caps = tickers.map((t) => Number(t.cap) || 1);
    const maxCap = Math.max(1, ...caps);

    function build() {
      orbs = tickers.map((t, i) => {
        const cap = Number(t.cap) || 1;
        const r = 12 + Math.sqrt(cap / maxCap) * 20;
        return {
          t, r,
          x: (W * (i + 0.5)) / tickers.length + (Math.random() - 0.5) * 24,
          y: H / 2 + (Math.random() - 0.5) * 30,
          vx: (Math.random() - 0.5) * 0.25, vy: (Math.random() - 0.5) * 0.25,
          phase: Math.random() * 6.2832,
        };
      });
    }
    function setup() {
      const dpr = Math.min(window.devicePixelRatio || 1, 2);
      const rect = canvas.getBoundingClientRect();
      W = rect.width; H = rect.height;
      if (!W || !H) return;
      canvas.width = W * dpr; canvas.height = H * dpr;
      ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
      build();
    }
    function step() {
      for (const o of orbs) {
        o.vx = (o.vx + (Math.random() - 0.5) * 0.03) * 0.985;
        o.vy = (o.vy + (Math.random() - 0.5) * 0.03) * 0.985;
        o.x += o.vx; o.y += o.vy;
      }
      for (let i = 0; i < orbs.length; i++) for (let j = i + 1; j < orbs.length; j++) {
        const a = orbs[i], b = orbs[j], dx = b.x - a.x, dy = b.y - a.y;
        const d = Math.hypot(dx, dy) || 0.01, min = a.r + b.r + 22;
        if (d < min) { const f = ((min - d) / d) * 0.018; a.vx -= dx * f; a.vy -= dy * f; b.vx += dx * f; b.vy += dy * f; }
      }
      const p = 6;
      for (const o of orbs) {
        if (o.x < o.r + p) { o.x = o.r + p; o.vx = Math.abs(o.vx); }
        if (o.x > W - o.r - p) { o.x = W - o.r - p; o.vx = -Math.abs(o.vx); }
        if (o.y < o.r + p + 12) { o.y = o.r + p + 12; o.vy = Math.abs(o.vy); }
        if (o.y > H - o.r - p - 14) { o.y = H - o.r - p - 14; o.vy = -Math.abs(o.vy); }
      }
    }
    function draw() {
      raf = requestAnimationFrame(draw);
      if (!orbs.length) { setup(); return; }
      try {
        frame++;
        step();
        ctx.clearRect(0, 0, W, H);
        ctx.lineWidth = 0.6;
        for (let i = 0; i < orbs.length; i++) for (let j = i + 1; j < orbs.length; j++) {
          const a = orbs[i], b = orbs[j], d = Math.hypot(b.x - a.x, b.y - a.y);
          if (d < 190) { ctx.strokeStyle = "rgba(155,229,100," + ((1 - d / 190) * 0.13).toFixed(3) + ")"; ctx.beginPath(); ctx.moveTo(a.x, a.y); ctx.lineTo(b.x, b.y); ctx.stroke(); }
        }
        for (const o of orbs) {
          const v = Number(o.t.changePct) || 0;
          const rgb = v > 0.2 ? "125,216,143" : v < -0.2 ? "229,115,107" : "201,210,190";
          const isSel = selRef.current === o.t.symbol;
          const isHov = hoverRef.current === o.t.symbol;
          const breathe = 0.6 + 0.4 * Math.sin(frame * 0.04 + o.phase);
          const glowR = o.r * (isSel || isHov ? 2.5 : 1.95);
          const halo = ctx.createRadialGradient(o.x, o.y, 0, o.x, o.y, glowR);
          halo.addColorStop(0, "rgba(" + rgb + "," + (0.3 + 0.2 * breathe + (isSel ? 0.2 : 0)) + ")");
          halo.addColorStop(1, "rgba(" + rgb + ",0)");
          ctx.fillStyle = halo; ctx.beginPath(); ctx.arc(o.x, o.y, glowR, 0, 6.2832); ctx.fill();
          ctx.fillStyle = "rgba(" + rgb + ",0.92)"; ctx.beginPath(); ctx.arc(o.x, o.y, o.r, 0, 6.2832); ctx.fill();
          if (isSel || isHov) { ctx.strokeStyle = themeRef.current === "light" ? "rgba(20,32,22,0.85)" : "rgba(236,240,234,0.9)"; ctx.lineWidth = 1.5; ctx.beginPath(); ctx.arc(o.x, o.y, o.r + 4, 0, 6.2832); ctx.stroke(); }
          ctx.textAlign = "center";
          if (o.r >= 15) {
            ctx.fillStyle = "rgba(10,13,10,0.95)";
            ctx.font = "700 " + Math.max(9, Math.min(12, o.r * 0.5)) + "px 'JetBrains Mono', monospace";
            ctx.textBaseline = "middle"; ctx.fillText(o.t.symbol, o.x, o.y);
          } else {
            ctx.fillStyle = themeRef.current === "light" ? "rgba(22,32,26,0.9)" : "rgba(230,235,228,0.85)";
            ctx.font = "700 10px 'JetBrains Mono', monospace";
            ctx.textBaseline = "bottom"; ctx.fillText(o.t.symbol, o.x, o.y - o.r - 3);
          }
          ctx.fillStyle = "rgba(" + rgb + ",0.95)";
          ctx.font = "600 10px 'JetBrains Mono', monospace"; ctx.textBaseline = "top";
          ctx.fillText((v >= 0 ? "+" : "") + v.toFixed(1) + "%", o.x, o.y + o.r + 4);
        }
      } catch { cancelAnimationFrame(raf); }
    }
    setup(); draw();

    const at = (e) => {
      const rect = canvas.getBoundingClientRect();
      const cx = (e.touches ? e.touches[0].clientX : e.clientX) - rect.left;
      const cy = (e.touches ? e.touches[0].clientY : e.clientY) - rect.top;
      return orbs.find((o) => Math.hypot(o.x - cx, o.y - cy) <= o.r + 6);
    };
    const onMove = (e) => { const o = at(e); hoverRef.current = o ? o.t.symbol : null; canvas.style.cursor = o ? "pointer" : "default"; };
    const onClick = (e) => { const o = at(e); if (o && onSel) onSel(o.t.symbol); };
    canvas.addEventListener("mousemove", onMove);
    canvas.addEventListener("click", onClick);
    let ro;
    if (typeof ResizeObserver !== "undefined") { ro = new ResizeObserver(() => setup()); ro.observe(canvas); }
    return () => {
      cancelAnimationFrame(raf);
      canvas.removeEventListener("mousemove", onMove);
      canvas.removeEventListener("click", onClick);
      if (ro) ro.disconnect();
    };
  }, [tickers]);

  return <canvas ref={canvasRef} className="ct-constellation" />;
}

/* ============================================================
   MARKETS OVERVIEW
   ============================================================ */
function SentimentView({ theme }) {
  const [sent, setSent] = useState(null);
  const [sentLoading, setSentLoading] = useState(false);
  const [sentErr, setSentErr] = useState(null);
  const [estimate, setEstimate] = useState(false);

  const [mkt, setMkt] = useState(null);
  const [mktLoading, setMktLoading] = useState(false);
  const [mktErr, setMktErr] = useState(false);

  const [med, setMed] = useState(null);
  const [medLoading, setMedLoading] = useState(false);
  const [medErr, setMedErr] = useState(false);

  const [selSym, setSelSym] = useState(null);

  const [brief, setBrief] = useState(null);
  const [briefLoading, setBriefLoading] = useState(false);
  const briefRan = useRef(false);

  const ran = useRef(false);
  const priceRef = useRef(null);
  const onPick = useCallback((sym) => {
    setSelSym(sym);
    if (priceRef.current) priceRef.current.scrollIntoView({ behavior: "smooth", block: "start" });
  }, []);

  const run = useCallback(() => {
    setBrief(null); briefRan.current = false;
    (async () => {
      setSentLoading(true); setSentErr(null); setEstimate(false);
      try {
        const { json, est } = await pullSentiment();
        if (!json) throw new Error("blank");
        setEstimate(est); setSent(json);
      } catch { setSentErr("Couldn't build the sentiment index just now."); }
      finally { setSentLoading(false); }
    })();

    (async () => {
      setMktLoading(true); setMktErr(false);
      try {
        const j = await pullMarket();
        if (!j) throw new Error("blank");
        setMkt(j);
      } catch { setMktErr(true); }
      finally { setMktLoading(false); }
    })();

    (async () => {
      setMedLoading(true); setMedErr(false);
      try {
        const j = await pullMedia();
        if (!j) throw new Error("blank");
        setMed(j);
      } catch { setMedErr(true); }
      finally { setMedLoading(false); }
    })();
  }, []);

  useEffect(() => {
    if (!ran.current) { ran.current = true; run(); }
  }, [run]);

  useEffect(() => {
    if (mkt && mkt.tickers && mkt.tickers.length && !selSym) setSelSym(mkt.tickers[0].symbol);
  }, [mkt, selSym]);

  useEffect(() => {
    if (briefRan.current) return;
    briefRan.current = true;
    (async () => {
      setBriefLoading(true);
      try { const j = await readCache("deskbrief"); if (j && j.thesis) setBrief(j); } catch { /* ignore */ }
      finally { setBriefLoading(false); }
    })();
  }, []);

  const anyLoading = sentLoading || mktLoading || medLoading;

  const briefDate = new Date().toLocaleDateString("en-US", { month: "short", day: "numeric" }).toUpperCase();

  return (
    <div className="ct-fade">
      <PriceTape tickers={mkt && mkt.tickers} index={mkt && mkt.index} onSel={onPick} />
      <div className="ct-sent-top">
        <div className="ct-hero-block">
          <div className="ct-eyebrow">
            <span className="ct-dot" /> CANNABIS SECTOR · MARKET INTELLIGENCE
          </div>
          <h2 className="ct-hero-h">
            {sentLoading ? "Reading the tape…" : sent ? sent.overall.label : "Sentiment Index"}
          </h2>
          <p className="ct-hero-sub">
            {sentLoading
              ? "Synthesizing equities, policy, demand and social signal into one read."
              : sent
              ? sent.overall.summary
              : "A live read on where the cannabis sector stands."}
          </p>
          <div className="ct-meta-row">
            <span className="ct-asof">{sent ? "AS OF " + (sent.asOf || "-").toUpperCase() : "-"}</span>
            {estimate && <span className="ct-badge-est">MODEL ESTIMATE · NO LIVE SEARCH</span>}
          </div>
        </div>
        <div className="ct-gauge-wrap">
          {sentLoading ? <GaugeLoading theme={theme} /> : sent ? <Gauge score={sent.overall.score} /> : <div className="ct-skel-gauge" />}
        </div>
      </div>

      {/* live stat strip */}
      <StatStrip mkt={mkt} loading={mktLoading} />

      {/* sector constellation */}
      <div className="ct-constel-band">
        <div className="ct-constel-label"><span className="ct-dot" /> SECTOR MAP · TAP AN ORB</div>
        {mktLoading && <div className="ct-chart-load"><span className="ct-spinner" /> mapping the sector…</div>}
        {mktErr && !mktLoading && <div className="ct-mini-err">Couldn't map the sector. <button className="ct-link" onClick={run}>Retry</button></div>}
        {mkt && !mktLoading && <Constellation tickers={mkt.tickers} sel={selSym} onSel={onPick} theme={theme} />}
      </div>

      {/* AI desk brief */}
      {(briefLoading || brief) && (
        <section className="ct-brief ct-rise">
          <div className="ct-brief-head">
            <span className="ct-brief-tag"><span className="ct-dot" /> DESK BRIEF</span>
            <span className="ct-brief-date">{briefDate} · AI-SYNTHESIZED</span>
          </div>
          {briefLoading && !brief ? (
            <div className="ct-brief-load"><span className="ct-spinner" /> writing the brief…</div>
          ) : brief ? (
            <>
              <p className="ct-brief-thesis">{brief.thesis}</p>
              {Array.isArray(brief.drivers) && brief.drivers.length > 0 && (
                <ul className="ct-brief-drivers">
                  {brief.drivers.map((d, i) => <li key={i}>{d}</li>)}
                </ul>
              )}
              {brief.stance && (
                <div className="ct-brief-stance"><span>POSITIONING</span> {brief.stance}</div>
              )}
            </>
          ) : null}
        </section>
      )}

      {sentErr && (
        <div className="ct-error">{sentErr} <button className="ct-link" onClick={run}>Try again</button></div>
      )}

      <div className="ct-cat-grid">
        {sentLoading
          ? CATEGORY_ORDER.map((c) => <SkeletonCard key={c} name={c} />)
          : (sent?.categories || []).map((cat, i) => {
              const meta = CATEGORY_META[cat.name] || {};
              return (
                <article className="ct-card ct-rise" key={cat.name + i} style={{ animationDelay: i * 70 + "ms" }}>
                  <header className="ct-card-head">
                    <span className="ct-glyph">{meta.glyph || "•"}</span>
                    <div>
                      <div className="ct-card-name">{cat.name}</div>
                      <div className="ct-card-blurb">{meta.blurb || ""}</div>
                    </div>
                    <span className="ct-card-score" style={{ color: sentColor(cat.score) }}>{cat.score}</span>
                  </header>
                  <div className="ct-bar">
                    <div className="ct-bar-fill" style={{ width: cat.score + "%", background: sentColor(cat.score) }} />
                  </div>
                  <div className="ct-card-label" style={{ color: sentColor(cat.score) }}>{(cat.label || "").toUpperCase()}</div>
                  <p className="ct-card-note">{cat.note}</p>
                  <ul className="ct-heads">
                    {(Array.isArray(cat.headlines) ? cat.headlines : cat.headline ? [{ title: cat.headline, source: cat.source }] : []).map((h, j) => (
                      <li key={j}><span className="ct-head-title">{h.title}</span><span className="ct-head-src">{h.source}</span></li>
                    ))}
                  </ul>
                </article>
              );
            })}
      </div>

      {/* PRICE ACTION, clickable ticker + chart */}
      <section className="ct-sec" ref={priceRef}>
        <SecHead label="PRICE ACTION" note="TAP A TICKER" />
        {mktLoading && <div className="ct-chart-load"><span className="ct-spinner" /> loading tickers…</div>}
        {mktErr && !mktLoading && <div className="ct-mini-err">Couldn't load the ticker board. <button className="ct-link" onClick={run}>Retry</button></div>}
        {mkt && !mktLoading && <TickerBoard tickers={mkt.tickers} sel={selSym} onSel={setSelSym} />}
      </section>

      {/* SECTOR MOVERS */}
      <section className="ct-sec">
        <SecHead label="SECTOR MOVERS" note={mkt ? "AS OF " + (mkt.asOf || "").toUpperCase() : ""} />
        {mktLoading && <LoadingRows n={4} />}
        {mktErr && !mktLoading && <div className="ct-mini-err">Couldn't load tickers right now. <button className="ct-link" onClick={run}>Retry</button></div>}
        {mkt && !mktLoading && <SectorMovers tickers={mkt.tickers} sel={selSym} onSel={setSelSym} />}
      </section>

      {/* NEWSROOM */}
      <section className="ct-sec">
        <SecHead label="NEWSROOM" />
        {medLoading && <LoadingRows n={4} />}
        {medErr && !medLoading && <div className="ct-mini-err">Couldn't load news.</div>}
        {med && !medLoading && (
          <>
            <HeadlineCrawl items={med.news || []} />
            <Newsroom items={med.news || []} />
          </>
        )}
      </section>

      {/* WATCH */}
      <section className="ct-sec">
        <SecHead label="WATCH" />
        {medLoading && <LoadingRows n={3} />}
        {med && !medLoading && <VideoGrid items={med.videos || []} />}
      </section>

      {/* SOCIAL */}
      <section className="ct-sec">
        <SecHead label="SOCIAL PULSE" />
        {medLoading && <LoadingRows n={3} />}
        {med && !medLoading && <SocialPulse items={med.social || []} />}
      </section>

      <p className="ct-disclaimer">
        {estimate
          ? "Live search was unavailable, sentiment shown is a model estimate. Informational only, not investment advice."
          : "AI-synthesized from live public sources. Informational only, not investment advice. Prices may be delayed or approximate."}
      </p>
    </div>
  );
}

/* ============================================================
   REGULATIONS Q&A VIEW
   ============================================================ */
function RegulationsView() {
  const [topic, setTopic] = useState("Federal rescheduling");
  const [messages, setMessages] = useState([]); // {role, text, sources}
  const [input, setInput] = useState("");
  const [busy, setBusy] = useState(false);
  const scrollRef = useRef(null);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [messages, busy]);

  const send = useCallback(
    async (raw) => {
      const q = (raw ?? input).trim();
      if (!q || busy) return;
      setInput("");
      const history = [...messages, { role: "user", text: q }];
      setMessages(history);
      setBusy(true);
      try {
        const sys =
          "You are a cannabis-sector policy analyst briefing investors and analysts. Current focus area: " +
          topic +
          ". Use web search to ground every answer in the most current laws, rules, regulatory actions, and legislative status, and lead with what changed most recently. Frame answers around what it means for the SECTOR and EQUITIES: catalysts, realistic timelines and odds, which companies or sub-sectors are most affected, and market impact. Be specific and concrete (cite bill names, agencies, dates, numbers). Keep answers focused: 2-4 short paragraphs or a tight list. End with a one-line 'Informational only, not investment or legal advice.' note. Do not invent citations.";
        const apiMsgs = history.map((m) => ({
          role: m.role,
          content: m.text,
        }));
        let resp;
        try {
          resp = await callClaude({ system: sys, tools: WEB_TOOL, messages: apiMsgs });
        } catch {
          // web search unavailable, answer from model knowledge instead of failing
          resp = await callClaude({ system: sys, messages: apiMsgs });
        }
        const { text, sources } = parseResponse(resp);
        setMessages((prev) => [...prev, { role: "assistant", text: text || "No answer returned.", sources }]);
      } catch (e) {
        setMessages((prev) => [
          ...prev,
          { role: "assistant", text: "⚠ " + (e.message || "Request failed.") + " Try again in a moment.", sources: [] },
        ]);
      } finally {
        setBusy(false);
      }
    },
    [input, messages, busy, topic]
  );

  return (
    <div className="ct-fade ct-reg">
      <div className="ct-reg-head">
        <div className="ct-eyebrow ct-amber">
          <span className="ct-dot ct-dot-amber" /> POLICY &amp; CATALYSTS
        </div>
        <h2 className="ct-hero-h">What moves the sector.</h2>
        <p className="ct-hero-sub">
          Regulatory catalysts read through an investor lens, timelines, odds, and who's exposed. Grounded in live sources.
        </p>
        <div className="ct-chips">
          {TOPICS.map((j) => (
            <button
              key={j}
              className={"ct-chip" + (topic === j ? " ct-chip-on" : "")}
              onClick={() => setTopic(j)}
            >
              {j}
            </button>
          ))}
        </div>
      </div>

      <div className="ct-thread" ref={scrollRef}>
        {messages.length === 0 && !busy && (
          <div className="ct-empty">
            <div className="ct-empty-mark">§</div>
            <p className="ct-empty-t">Start with a question</p>
            <div className="ct-starters">
              {STARTERS.map((s) => (
                <button key={s} className="ct-starter" onClick={() => send(s)}>
                  {s}
                </button>
              ))}
            </div>
          </div>
        )}

        {messages.map((m, i) => (
          <div key={i} className={"ct-msg ct-msg-" + m.role}>
            <div className="ct-msg-who">{m.role === "user" ? "YOU" : "DESK"}</div>
            <div className="ct-msg-body">
              {m.role === "assistant" ? renderRich(m.text) : <p className="ct-p">{m.text}</p>}
              {m.sources && m.sources.length > 0 && (
                <div className="ct-sources">
                  <div className="ct-sources-h">SOURCES</div>
                  {m.sources.slice(0, 6).map((s, j) => (
                    <a key={j} href={s.url} target="_blank" rel="noopener noreferrer" className="ct-source">
                      <span className="ct-source-n">{j + 1}</span>
                      <span className="ct-source-t">{s.title}</span>
                    </a>
                  ))}
                </div>
              )}
            </div>
          </div>
        ))}

        {busy && (
          <div className="ct-msg ct-msg-assistant">
            <div className="ct-msg-who">DESK</div>
            <div className="ct-msg-body">
              <div className="ct-typing">
                <span /> <span /> <span /> searching current sources…
              </div>
            </div>
          </div>
        )}
      </div>

      <div className="ct-composer">
        <textarea
          className="ct-input"
          rows={1}
          placeholder={"Ask about " + topic + ", impact, timing, who's exposed…"}
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyDown={(e) => {
            if (e.key === "Enter" && !e.shiftKey) {
              e.preventDefault();
              send();
            }
          }}
        />
        <button className="ct-send" onClick={() => send()} disabled={busy || !input.trim()}>
          {busy ? "…" : "↑"}
        </button>
      </div>
    </div>
  );
}

/* ============================================================
   NEXT-PHASE DESKS, Home, Healthcare, Catalysts, Briefings
   Shared lazy-load + in-memory cache so tab switches don't refetch.
   ============================================================ */
const DESK_CACHE = {};
function useDeskData(key, fetcher) {
  const [data, setData] = useState(() => DESK_CACHE[key] || null);
  const [loading, setLoading] = useState(() => !DESK_CACHE[key]);
  const [err, setErr] = useState(false);
  const fRef = useRef(fetcher);
  fRef.current = fetcher;
  const reload = useCallback(() => {
    setLoading(true); setErr(false);
    Promise.resolve()
      .then(() => fRef.current())
      .then((j) => { if (j) { DESK_CACHE[key] = j; setData(j); } else { setErr(true); } })
      .catch(() => setErr(true))
      .finally(() => setLoading(false));
  }, [key]);
  useEffect(() => {
    if (DESK_CACHE[key]) { setData(DESK_CACHE[key]); setLoading(false); setErr(false); }
    else { setData(null); reload(); }
  }, [key, reload]);
  return { data, loading, err, reload };
}

