function CatalystList({ items, full }) {
  const sorted = (items || []).slice().sort((a, b) => {
    const da = Date.parse(a.date), db = Date.parse(b.date);
    if (isNaN(da) && isNaN(db)) return 0;
    if (isNaN(da)) return 1;
    if (isNaN(db)) return -1;
    return da - db;
  });
  return (
    <div className="ct-cat-list">
      {sorted.map((c, i) => (
        <div className="ct-cat-row" key={i}>
          <div className="ct-cat-date">{fmtDate(c.date)}<span className="ct-cat-when">{whenLabel(c.date)}</span></div>
          <div className="ct-cat-main">
            <div className="ct-cat-label">{c.label}</div>
            {full && c.note ? <div className="ct-cat-note">{c.note}</div> : null}
            {full ? (
              <div className="ct-cat-meta">
                {c.category ? <span className="ct-cat-cat">{c.category}</span> : null}
                {c.impact ? (
                  <span className="ct-impact" style={{ color: impactColor(c.impact), borderColor: impactColor(c.impact), border: "1px solid" }}>
                    {c.impact} impact
                  </span>
                ) : null}
                {(c.tickers || []).slice(0, 4).map((t, j) => <span className="ct-cat-tkr" key={j}>{t}</span>)}
              </div>
            ) : null}
          </div>
        </div>
      ))}
    </div>
  );
}

