class ErrorBoundary extends React.Component {
  constructor(props) { super(props); this.state = { err: null }; }
  static getDerivedStateFromError(err) { return { err }; }
  componentDidCatch(err, info) { console.error("CannaTracker error:", err, info); }
  render() {
    if (this.state.err) {
      return (
        <div className="ct-shell" style={{ paddingTop: 48 }}>
          <div className="ct-error">
            A render error occurred: {String((this.state.err && this.state.err.message) || this.state.err)}{" "}
            <button className="ct-link" onClick={() => this.setState({ err: null })}>Retry</button>
          </div>
        </div>
      );
    }
    return this.props.children;
  }
}

